INSERT INTO game (
    game_id, source, path, name, `desc`, translated_name, translated_desc, image, video, marquee, thumbnail, manual,
    box_front, box_back, box_spine, box_full, cartridge, logo, bezel, panel, cabinet_left, cabinet_right, tile, banner, steam, poster, background, music, screenshot, titlescreen, box3d, steamgrid, fanart, boxtexture, supporttexture, platform_type, hash,
    rating, releasedate, developer, publisher, genre, players, crc32, md5, lang, genreid, platform_id, sort_by, scraped, edited, `exists`, absolute_path, platform_path
) VALUES (
    #{gameId}, #{source}, #{path}, #{name}, #{desc}, #{translatedName}, #{translatedDesc}, #{image}, #{video}, #{marquee}, #{thumbnail}, #{manual},
    #{boxFront}, #{boxBack}, #{boxSpine}, #{boxFull}, #{cartridge}, #{logo}, #{bezel}, #{panel}, #{cabinetLeft}, #{cabinetRight}, #{tile}, #{banner}, #{steam}, #{poster}, #{background}, #{music}, #{screenshot}, #{titlescreen}, #{box3d}, #{steamgrid}, #{fanart}, #{boxtexture}, #{supporttexture}, #{platformType}, #{hash},
    #{rating}, #{releasedate}, #{developer}, #{publisher}, #{genre}, #{players}, #{crc32}, #{md5}, #{lang}, #{genreid}, #{platformId}, #{sortBy}, #{scraped, jdbcType=BOOLEAN}, #{edited, jdbcType=BOOLEAN}, #{exists, jdbcType=BOOLEAN}, #{absolutePath}, #{platformPath}
)

INSERT INTO game (
    game_id, source, path, name, `desc`, translated_name, translated_desc, image, video, marquee, thumbnail, manual,
    box_front, box_back, box_spine, box_full, cartridge, logo, bezel, panel, cabinet_left, cabinet_right, tile, banner, steam, poster, background, music, screenshot, titlescreen, box3d, steamgrid, fanart, boxtexture, supporttexture, platform_type, hash,
    rating, releasedate, developer, publisher, genre, players, crc32, md5, lang, genreid, platform_id, scraped, edited, `exists`, absolute_path, platform_path
) VALUES

    (
        #{game.gameId}, #{game.source}, #{game.path}, #{game.name}, #{game.desc}, #{game.translatedName}, #{game.translatedDesc}, #{game.image}, #{game.video}, #{game.marquee}, #{game.thumbnail}, #{game.manual},
        #{game.boxFront}, #{game.boxBack}, #{game.boxSpine}, #{game.boxFull}, #{game.cartridge}, #{game.logo}, #{game.bezel}, #{game.panel}, #{game.cabinetLeft}, #{game.cabinetRight}, #{game.tile}, #{game.banner}, #{game.steam}, #{game.poster}, #{game.background}, #{game.music}, #{game.screenshot}, #{game.titlescreen}, #{game.box3d}, #{game.steamgrid}, #{game.fanart}, #{game.boxtexture}, #{game.supporttexture}, #{game.platformType}, #{game.hash},
        #{game.rating}, #{game.releasedate}, #{game.developer}, #{game.publisher}, #{game.genre}, #{game.players}, #{game.crc32}, #{game.md5}, #{game.lang}, #{game.genreid}, #{game.platformId}, #{game.scraped, jdbcType=BOOLEAN}, #{game.edited, jdbcType=BOOLEAN}, #{game.exists, jdbcType=BOOLEAN}, #{game.absolutePath}, #{game.platformPath}
    )

mapper.select:
SELECT g.* FROM game g LEFT JOIN platform p ON g.platform_id = p.id WHERE 1=1
AND g.platform_id = #{platformId}
AND g.name IS NOT NULL AND g.name != '' AND (g.`desc` IS NOT NULL AND g.`desc` != '' OR g.translated_desc IS NOT NULL AND g.translated_desc != '') AND g.image IS NOT NULL AND g.image != '' AND g.video IS NOT NULL AND g.video != '' AND g.marquee IS NOT NULL AND g.marquee != '' AND g.thumbnail IS NOT NULL AND g.thumbnail != '' AND g.manual IS NOT NULL AND g.manual != ''
AND g.name IS NOT NULL AND g.name != '' AND (g.`desc` IS NOT NULL AND g.`desc` != '' OR g.translated_desc IS NOT NULL AND g.translated_desc != '') AND (g.image IS NULL OR g.image = '' OR g.video IS NULL OR g.video = '' OR g.marquee IS NULL OR g.marquee = '' OR g.thumbnail IS NULL OR g.thumbnail = '' OR g.manual IS NULL OR g.manual = '')
AND NOT ( (g.name IS NOT NULL AND g.name != '' AND (g.`desc` IS NOT NULL AND g.`desc` != '' OR g.translated_desc IS NOT NULL AND g.translated_desc != '') AND g.image IS NOT NULL AND g.image != '' AND g.video IS NOT NULL AND g.video != '' AND g.marquee IS NOT NULL AND g.marquee != '' AND g.thumbnail IS NOT NULL AND g.thumbnail != '' AND g.manual IS NOT NULL AND g.manual != '') OR (g.name IS NOT NULL AND g.name != '' AND (g.`desc` IS NOT NULL AND g.`desc` != '' OR g.translated_desc IS NOT NULL AND g.translated_desc != '') AND (g.image IS NULL OR g.image = '' OR g.video IS NULL OR g.video = '' OR g.marquee IS NULL OR g.marquee = '' OR g.thumbnail IS NULL OR g.thumbnail = '' OR g.manual IS NULL OR g.manual = '')) )
ORDER BY g.name LIMIT #{limit} OFFSET #{offset}
